--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -2447,6 +2447,88 @@
+// ─── Particle system for environmental effects ──────────────────────
+
+interface Particle {
+  x: number;
+  y: number;
+  vx: number;
+  vy: number;
+  life: number;
+  maxLife: number;
+  color: string;
+  size: number;
+  type: 'dust' | 'spark' | 'drip';
+}
+
+const particles: Particle[] = [];
+
+/**
+ * Spawn a new particle of a given type at position (x,y) with velocity (vx,vy).
+ * @param type Particle effect type: 'dust', 'spark', or 'drip'
+ * @param x Initial x position
+ * @param y Initial y position
+ * @param vx Initial x velocity
+ * @param vy Initial y velocity
+ * @param color Particle color string
+ * @param size Particle size in pixels
+ * @param life Particle lifetime in frames
+ */
+function spawnParticle(
+  type: 'dust' | 'spark' | 'drip',
+  x: number,
+  y: number,
+  vx: number,
+  vy: number,
+  color: string,
+  size: number,
+  life: number,
+) {
+  if (particles.length > 200) return; // limit total particles for performance
+  particles.push({ x, y, vx, vy, life, maxLife: life, color, size, type });
+}
+
+/**
+ * Update all particles' positions and lifetimes.
+ * Remove particles that have expired.
+ */
+function updateParticles() {
+  for (let i = particles.length - 1; i >= 0; i--) {
+    const p = particles[i];
+    p.x += p.vx;
+    p.y += p.vy;
+    p.life--;
+    // Apply gravity or slow drift depending on type
+    if (p.type === 'drip') {
+      p.vy += 0.05; // gravity for drips
+    } else if (p.type === 'dust') {
+      p.vx += (Math.random() - 0.5) * 0.02;
+      p.vy += (Math.random() - 0.5) * 0.01;
+    } else if (p.type === 'spark') {
+      p.vx *= 0.98;
+      p.vy *= 0.98;
+      p.vy -= 0.02; // sparks rise and slow down
+    }
+    if (p.life <= 0) {
+      particles.splice(i, 1);
+    }
+  }
+}
+
+/**
+ * Draw all active particles on the canvas context.
+ * @param ctx CanvasRenderingContext2D
+ */
+function drawParticles(ctx: CanvasRenderingContext2D) {
+  for (const p of particles) {
+    ctx.globalAlpha = p.life / p.maxLife;
+    ctx.fillStyle = p.color;
+    ctx.beginPath();
+    if (p.type === 'drip') {
+      // Draw water droplet as small ellipse
+      ctx.ellipse(Math.round(p.x), Math.round(p.y), p.size * 0.6, p.size, 0, 0, Math.PI * 2);
+      ctx.fill();
+    } else {
+      // Draw dust and sparks as squares
+      ctx.fillRect(Math.round(p.x), Math.round(p.y), p.size, p.size);
+    }
+  }
+  ctx.globalAlpha = 1;
+}
+
+/**
+ * Spawn environmental particles for different effect types at given bounds.
+ * Call this every frame to generate new particles.
+ * @param effectType 'dust' | 'spark' | 'drip'
+ * @param bounds { x, y, w, h } bounding box for spawning particles
+ * @param frame Current animation frame count
+ */
+function spawnEnvironmentalParticles(effectType: 'dust' | 'spark' | 'drip', bounds: { x: number; y: number; w: number; h: number }, frame: number) {
+  switch (effectType) {
+    case 'dust':
+      // Dust motes floating slowly in light beams
+      if (particles.filter(p => p.type === 'dust').length < 50 && Math.random() < 0.1) {
+        const x = bounds.x + Math.random() * bounds.w;
+        const y = bounds.y + Math.random() * bounds.h;
+        const vx = (Math.random() - 0.5) * 0.1;
+        const vy = (Math.random() - 0.5) * 0.05;
+        const color = 'rgba(255, 255, 200, 0.6)';
+        const size = 1 + Math.random();
+        const life = 100 + Math.floor(Math.random() * 60);
+        spawnParticle('dust', x, y, vx, vy, color, size, life);
+      }
+      break;
+    case 'spark':
+      // Fireplace or forge sparks rising and fading
+      if (particles.filter(p => p.type === 'spark').length < 40 && Math.random() < 0.15) {
+        const x = bounds.x + Math.random() * bounds.w;
+        const y = bounds.y + bounds.h - 4;
+        const vx = (Math.random() - 0.5) * 0.3;
+        const vy = -0.7 - Math.random() * 0.3;
+        const color = `rgba(255, ${140 + Math.floor(Math.random() * 60)}, 0, 1)`;
+        const size = 1 + Math.random() * 1.5;
+        const life = 40 + Math.floor(Math.random() * 20);
+        spawnParticle('spark', x, y, vx, vy, color, size, life);
+      }
+      break;
+    case 'drip':
+      // Water drips falling in dungeon
+      if (particles.filter(p => p.type === 'drip').length < 30 && Math.random() < 0.12) {
+        const x = bounds.x + Math.random() * bounds.w;
+        const y = bounds.y + 2;
+        const vx = 0;
+        const vy = 0.7 + Math.random() * 0.3;
+        const color = 'rgba(180, 220, 255, 0.8)';
+        const size = 1 + Math.random();
+        const life = 50 + Math.floor(Math.random() * 20);
+        spawnParticle('drip', x, y, vx, vy, color, size, life);
+      }
+      break;
+  }
+}
+
